class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers: List[str], topics: List[str], 
                 group_id: str = 'financial-transaction-group',
                 auto_offset_reset: str = 'earliest',
                 enable_auto_commit: bool = True):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics
        self.group_id = group_id
        self.auto_offset_reset = auto_offset_reset
        self.enable_auto_commit = enable_auto_commit
        self.consumer = None
        self.handlers: Dict[str, List[MessageHandler]] = {}
        self.running = False
        self.executor = ThreadPoolExecutor(max_workers=10)
        self.lock = threading.Lock()
        
    def register_handler(self, message_type: str, handler: MessageHandler):
        with self.lock:
            if message_type not in self.handlers:
                self.handlers[message_type] = []
            self.handlers[message_type].append(handler)
            logger.info(f"Registered handler {handler.__class__.__name__} for message type: {message_type}")
    
    def deserialize_message(self, message_value: bytes) -> Dict[str, Any]:
        try:
            decoded = message_value.decode('utf-8')
            data = json.loads(decoded)
            
            if 'serialized_object' in data:
                serialized_data = base64.b64decode(data['serialized_object'])
                obj = pickle.loads(serialized_data)
                if hasattr(obj, 'to_dict'):
                    return obj.to_dict()
                elif isinstance(obj, dict):
                    return obj
                else:
                    return {'data': obj}
            
            return data
        except json.JSONDecodeError:
            try:
                obj = pickle.loads(message_value)
                if hasattr(obj, 'to_dict'):
                    return obj.to_dict()
                elif isinstance(obj, dict):
                    return obj
                else:
                    return {'data': obj}
            except Exception as e:
                logger.error(f"Failed to deserialize message: {e}")
                return {}
    
    def process_message(self, message):
        try:
            deserialized_data = self.deserialize_message(message.value)
            
            if not deserialized_data:
                logger.warning(f"Empty message received from topic {message.topic}")
                return
            
            message_type = deserialized_data.get('transaction_type', 'unknown')
            
            logger.info(f"Received message from topic {message.topic}, partition {message.partition}, offset {message.offset}")
            logger.info(f"Message type: {message_type}, Transaction ID: {deserialized_data.get('transaction_id', 'N/A')}")
            
            handlers = self.handlers.get(message_type, [])
            handlers.extend(self.handlers.get('*', []))
            
            if not handlers:
                logger.warning(f"No handlers registered for message type: {message_type}")
                return
            
            for handler in handlers:
                try:
                    result = handler.handle(deserialized_data)
                    if result:
                        logger.info(f"Handler {handler.__class__.__name__} processed message successfully")
                    else:
                        logger.warning(f"Handler {handler.__class__.__name__} returned False")
                except Exception as e:
                    logger.error(f"Handler {handler.__class__.__name__} failed: {e}")
        
        except Exception as e:
            logger.error(f"Error processing message: {e}")
    
    def start(self):
        try:
            self.consumer = KafkaConsumer(
                *self.topics,
                bootstrap_servers=self.bootstrap_servers,
                group_id=self.group_id,
                auto_offset_reset=self.auto_offset_reset,
                enable_auto_commit=self.enable_auto_commit,
                value_deserializer=lambda m: m
            )
            
            self.running = True
            logger.info(f"Consumer started. Subscribed to topics: {self.topics}")
            
            for message in self.consumer:
                if not self.running:
                    break
                self.executor.submit(self.process_message, message)
        
        except Exception as e:
            logger.error(f"Consumer error: {e}")
        finally:
            self.stop()
    
    def stop(self):
        self.running = False
        if self.consumer:
            self.consumer.close()
            logger.info("Consumer stopped")
        self.executor.shutdown(wait=True)


class TransactionProcessor:
    def __init__(self, bootstrap_servers: List[str]):
        self.consumer = FinancialTransactionConsumer(
            bootstrap_servers=bootstrap_servers,
            topics=['financial-transactions', 'payment-events', 'fraud-alerts'],
            group_id='transaction-processor-group'
        )
        
        self.consumer.register_handler('payment', PaymentHandler())
        self.consumer.register_handler('refund', RefundHandler())
        self.consumer.register_handler('transfer', TransferHandler())
        self.consumer.register_handler('*', FraudDetectionHandler())
    
    def start(self):
        logger.info("Starting Transaction Processor")
        self.consumer.start()
    
    def stop(self):
        self.consumer.stop()


